using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Tools -----------------------------------------------------------

var noteTaker = new NoteTaker();

List<AITool> tools =
[
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(noteTaker.SaveNote),
    AIFunctionFactory.Create(noteTaker.GetAllNotes),
];

// --- Chat client (plain – ChatClientAgent handles tool dispatch) -----

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Agent -----------------------------------------------------------

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Given a topic you MUST:

        1. Perform at least 3 different web searches to gather broad information.
        2. After each search, save the most important findings as a note
           (include the source URL when available).
        3. Once you have enough material, retrieve all your notes and
           compose a well-organized summary with these sections:
             • Overview
             • Key Findings
             • Sources

        Be thorough but concise. Always cite sources.
        """,
    name: "ResearchAgent",
    description: "Researches a topic using web search and note-taking tools.",
    tools: tools);

// --- Run -------------------------------------------------------------

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return 1;
}

Console.WriteLine($"\n🔬  Researching: {topic}\n");

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0.3f,
        MaxOutputTokens = 4096,
    }));

Console.WriteLine();
Console.WriteLine("═══════════════════════════════════════════════");
Console.WriteLine("              RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════");
Console.WriteLine();

foreach (var message in response.Messages)
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
    {
        Console.WriteLine(message.Text);
    }
}

return 0;

// =====================================================================
//  Tool implementations
// =====================================================================

/// <summary>Searches the web via DuckDuckGo and returns text snippets.</summary>
internal static partial class WebSearchTool
{
    private static readonly HttpClient s_http = CreateHttpClient();

    [Description("Search the web for information. Returns the top results with titles, snippets, and URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍  Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var html = await s_http.GetStringAsync(
                $"https://html.duckduckgo.com/html/?q={encoded}");

            return ParseResults(html, maxResults: 5);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string ParseResults(string html, int maxResults)
    {
        var sb = new StringBuilder();
        int count = 0;

        // Match DuckDuckGo result blocks
        foreach (Match m in ResultPattern().Matches(html))
        {
            if (++count > maxResults) break;

            var title = StripHtml(m.Groups["title"].Value);
            var snippet = StripHtml(m.Groups["snippet"].Value);
            var rawUrl = m.Groups["url"].Value;

            // DuckDuckGo wraps URLs in a redirect; extract the real one
            var url = ExtractUrl(rawUrl);

            sb.AppendLine($"[{count}] {title}");
            sb.AppendLine($"    URL: {url}");
            sb.AppendLine($"    {snippet}");
            sb.AppendLine();
        }

        return count > 0
            ? sb.ToString()
            : "No results found.";
    }

    private static string ExtractUrl(string raw)
    {
        // DuckDuckGo uses //duckduckgo.com/l/?uddg=<encoded-url>&...
        var match = UddgPattern().Match(raw);
        if (match.Success)
        {
            return Uri.UnescapeDataString(match.Groups[1].Value);
        }

        return WebUtility.HtmlDecode(raw);
    }

    private static string StripHtml(string value)
    {
        var decoded = WebUtility.HtmlDecode(value);
        return HtmlTagPattern().Replace(decoded, "").Trim();
    }

    private static HttpClient CreateHttpClient()
    {
        var client = new HttpClient();
        client.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
        client.Timeout = TimeSpan.FromSeconds(15);
        return client;
    }

    [GeneratedRegex(
        @"<a[^>]+class=""result__a""[^>]*href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?" +
        @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ResultPattern();

    [GeneratedRegex(@"uddg=([^&]+)")]
    private static partial Regex UddgPattern();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex HtmlTagPattern();
}

/// <summary>In-memory note-taking tool for the research agent.</summary>
internal sealed class NoteTaker
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note for later reference. Use this to record important findings.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The content / findings to save")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        Console.WriteLine($"  📝  Note saved: \"{title}\"");
        return $"Note '{title}' saved successfully ({_notes.Count} total notes).";
    }

    [Description("Retrieve all research notes saved so far.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== {_notes.Count} Research Notes ===\n");

        for (int i = 0; i < _notes.Count; i++)
        {
            var n = _notes[i];
            sb.AppendLine($"--- Note {i + 1}: {n.Title} ---");
            sb.AppendLine(n.Content);
            sb.AppendLine();
        }

        Console.WriteLine($"  📋  Retrieved {_notes.Count} notes");
        return sb.ToString();
    }

    private sealed record Note(string Title, string Content, DateTime SavedAt);
}

